#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int isPermut(long long x) {
    long long y = 2 * x;
    int freqX[10] = {0}, freqY[10] = {0};
    int digitsX = 0, digitsY = 0;
    long long tempX = x, tempY = y;
    while (tempX > 0) {
        freqX[tempX % 10]++;
        tempX /= 10;
        digitsX++;
    }
    while (tempY > 0) {
        freqY[tempY % 10]++;
        tempY /= 10;
        digitsY++;
    }
    if (digitsX != digitsY) return 0;
    for (int i = 0; i < 10; i++) {
        if (freqX[i] != freqY[i]) return 0;
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long A, B;
        scanf("%lld %lld", &A, &B);
        int count = 0;
        for (long long i = A; i <= B; i++) {
            if (isPermut(i)) count++;
        }
        printf("%d\n", count);
    }
    return 0;
}

